transform_js:
const axisData = []; const values = [];
rawData.rows.forEach(r => {
  axisData.push(r.time);
  values.push(r.value);
});
transformedData = { axisData, values, threshold: 80 };

echarts_js:
option = {
  title: {
    text: 'Server CPU Load (Threshold Alert)',
    left: 'center'
  },
  tooltip: {
    trigger: 'axis'
  },
  grid: { left: '5%', right: '10%', bottom: '15%', containLabel: true },
  xAxis: {
    type: 'category',
    boundaryGap: false,
    data: transformedData.axisData
  },
  yAxis: {
    type: 'value',
    max: 100
  },
  // VisualMapを用いた値に基づく色の分断
  visualMap: {
    type: 'piecewise',
    show: false,
    dimension: 1,
    pieces: [
      { lte: transformedData.threshold, color: '#314656' },
      { gt: transformedData.threshold, color: '#cc0033' }
    ]
  },
  series: [
    {
      name: 'CPU Load',
      type: 'line',
      smooth: true,
      data: transformedData.values,
      markLine: {
        silent: true,
        lineStyle: {
          color: '#cc0033',
          type: 'dashed'
        },
        data: [
          { yAxis: transformedData.threshold }
        ]
      }
    }
  ]
};
